$ErrorActionPreference='Stop';$root=Split-Path -Parent $PSScriptRoot;$sandbox=Join-Path ([IO.Path]::GetTempPath()) ('ueef-recipe-'+[guid]::NewGuid().ToString('N'));try{New-Item -ItemType Directory -Path $sandbox|Out-Null;$r=(& (Join-Path $root 'scripts\new-refactor-recipe.ps1') -Title 'Extract Service' -Target 'src/service' -Root $sandbox -Json|Out-String)|ConvertFrom-Json;$t=Get-Content $r.path -Raw;if($r.automaticExecution -or $t -notmatch 'Characterization baseline' -or $t -notmatch 'Rollback'){throw 'Refactor recipe contract failed.'};Write-Host 'Refactor recipe tests passed'}finally{if(Test-Path $sandbox){Remove-Item $sandbox -Recurse -Force}}
